function initializePopup(){loadStats(),setupEventListeners()}function setupEventListeners(){document.getElementById("open-main").addEventListener("click",()=>{chrome.runtime.sendMessage({action:"OPEN_MAIN_VIEWER"},()=>{window.close()})}),document.getElementById("sync-now").addEventListener("click",()=>{const e=document.getElementById("sync-now");e.disabled=!0,e.innerHTML='\n      <svg width="16" height="16" viewBox="0 0 16 16" fill="none" class="spin">\n        <circle cx="8" cy="8" r="6" stroke="currentColor" stroke-width="2" stroke-dasharray="12" stroke-dashoffset="12">\n          <animate attributeName="stroke-dasharray" values="0 31.416;31.416 0" dur="1.5s" repeatCount="indefinite"/>\n          <animate attributeName="stroke-dashoffset" values="0;-31.416" dur="1.5s" repeatCount="indefinite"/>\n        </circle>\n      </svg>\n      Syncing...\n    ',chrome.runtime.sendMessage({action:"SYNC_WITH_INSTAGRAM"},()=>{showStatus("Syncing started!","syncing"),setTimeout(()=>{e.disabled=!1,e.innerHTML='\n          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">\n            <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0118.8-4.3M22 12.5a10 10 0 01-18.8 4.3"/>\n          </svg>\n          Sync Now\n        ',window.close()},1e3)})}),document.getElementById("clear-storage").addEventListener("click",handleClearStorage)}function loadStats(){chrome.runtime.sendMessage({action:"GET_POSTS_COUNT"},e=>{if(chrome.runtime.lastError)return console.error("Error loading stats:",chrome.runtime.lastError),void(document.getElementById("total-posts").textContent="0");document.getElementById("total-posts").textContent=e?.count||0}),chrome.runtime.sendMessage({action:"GET_COLLECTIONS"},e=>{if(chrome.runtime.lastError)return console.error("Error loading collections:",chrome.runtime.lastError),void(document.getElementById("total-collections").textContent="0");document.getElementById("total-collections").textContent=e?.collections?.length||0})}function handleClearStorage(){if(confirm("Clear all stored data?\n\n• All posts\n• All media\n• All collections\n\nThis cannot be undone!")){const e=document.getElementById("clear-storage");e.disabled=!0,e.innerHTML='\n      <svg width="16" height="16" viewBox="0 0 16 16" fill="none" class="spin">\n        <circle cx="8" cy="8" r="6" stroke="currentColor" stroke-width="2" stroke-dasharray="12" stroke-dashoffset="12">\n          <animate attributeName="stroke-dasharray" values="0 31.416;31.416 0" dur="1.5s" repeatCount="indefinite"/>\n          <animate attributeName="stroke-dashoffset" values="0;-31.416" dur="1.5s" repeatCount="indefinite"/>\n        </circle>\n      </svg>\n      Clearing...\n    ',chrome.runtime.sendMessage({action:"CLEAR_STORAGE"},t=>{if(chrome.runtime.lastError||!t?.success)return console.error("Error clearing storage:",chrome.runtime.lastError||t?.error),showStatus("Error clearing storage","error"),e.disabled=!1,void(e.innerHTML='\n          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">\n            <path d="M4 4L12 12M12 4L4 12" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>\n          </svg>\n          Clear Storage\n        ');showStatus("Storage cleared!","success"),loadStats(),e.disabled=!1,e.innerHTML='\n        <svg width="16" height="16" viewBox="0 0 16 16" fill="none">\n          <path d="M4 4L12 12M12 4L4 12" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>\n        </svg>\n        Clear Storage\n      ',setTimeout(()=>{hideStatus()},3e3)})}}function showStatus(e,t="info"){const n=document.getElementById("popup-status");n.textContent=e,n.className=`popup-status ${t}`,n.style.display="block"}function hideStatus(){document.getElementById("popup-status").style.display="none"}document.addEventListener("DOMContentLoaded",()=>{initializePopup()});